svg.script:
// Seeded pseudo-random for reproducibility
var seed = 42;
function rand() { seed = (seed * 16807 + 0) % 2147483647; return (seed - 1) / 2147483646; }
function noise() { return (rand() - 0.5) * 2; }

var W = 720, H = 230, OX = 50, OY = 20;
var midY = OY + H / 2;
var totalTime = 20; // seconds
var samplesPerSec = 50;
var totalSamples = totalTime * samplesPerSec;

// Chair stand: 5 bursts between ~3s and ~17s
// Each burst ~2s with ~1s gap
// burst centers at: 4.5, 7.5, 10.5, 13.0, 15.5
var bursts = [
  {start: 3.0, end: 5.0},
  {start: 6.0, end: 8.0},
  {start: 9.0, end: 11.0},
  {start: 12.0, end: 13.8},
  {start: 14.8, end: 16.8}
];

function inBurst(t) {
  for (var i = 0; i < bursts.length; i++) {
    var b = bursts[i];
    if (t >= b.start && t <= b.end) {
      // envelope: ramp up and down
      var dur = b.end - b.start;
      var frac = (t - b.start) / dur;
      var env = Math.sin(frac * Math.PI);
      return env;
    }
  }
  return 0;
}

function genSignal(ampRest, ampBurst, freqRest, freqBurst, phaseOff, noiseScale) {
  var pts = [];
  for (var i = 0; i < totalSamples; i++) {
    var t = i / samplesPerSec;
    var env = inBurst(t);
    var restSig = ampRest * Math.sin(2 * Math.PI * freqRest * t + phaseOff);
    var burstSig = ampBurst * (
      Math.sin(2 * Math.PI * freqBurst * t + phaseOff) * 0.6 +
      Math.sin(2 * Math.PI * freqBurst * 1.7 * t + phaseOff * 0.5) * 0.25 +
      Math.sin(2 * Math.PI * freqBurst * 3.1 * t + phaseOff * 1.3) * 0.15
    );
    var val = restSig * (1 - env) + burstSig * env + noise() * noiseScale * (0.3 + env * 0.7);
    // Add sharp peak at transitions
    if (env > 0.1 && env < 0.4) val += ampBurst * 0.3 * Math.sin(2 * Math.PI * 2.5 * t);
    pts.push(val);
  }
  return pts;
}

var xSig = genSignal(0.02, 0.30, 0.1, 0.7, 0, 0.025);
var ySig = genSignal(0.015, 0.12, 0.12, 0.5, 1.5, 0.018);
var zSig = genSignal(0.02, 0.28, 0.08, 0.8, 3.0, 0.022);

function toPath(sig) {
  var maxAmp = 0.45;
  var d = "";
  for (var i = 0; i < sig.length; i++) {
    var x = OX + (i / totalSamples) * W;
    var y = midY - (sig[i] / maxAmp) * (H / 2 - 10);
    d += (i === 0 ? "M" : "L") + x.toFixed(1) + "," + y.toFixed(1);
  }
  return d;
}

document.getElementById("pathX").setAttribute("d", toPath(xSig));
document.getElementById("pathY").setAttribute("d", toPath(ySig));
document.getElementById("pathZ").setAttribute("d", toPath(zSig));
